  app.post('/api/admin/upload-source', express.json({ limit: '100mb' }), (req, res) => {
    try {
      const { filename, base64 } = req.body;
      if (!base64) {
        return res.status(400).json({ error: 'No file data received.' });
      }
      const buffer = Buffer.from(base64, 'base64');
      const filepath = '/tmp/uploaded-source.zip';

      const dir = path.dirname(filepath);
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }

      fs.writeFileSync(filepath, buffer);
      console.log(`Admin uploaded source code ZIP: ${filename} (${buffer.length} bytes)`);
      res.json({ success: true, filename, size: buffer.length });
    } catch (err) {
      console.error("Failed to upload source file:", err);
      res.status(500).json({ error: err.message || 'Failed to write source ZIP file.' });
    }
  });

  // ==========================================
  // SOURCE CODE EXPORT / ZIP GENERATION
  // ==========================================
  app.get('/api/download-source', (req, res) => {
    const config = getPaymentConfig();
    
    // Check if download verification is active (customPaymentLink is set)
    if (config.customPaymentLink && config.customPaymentLink.trim()) {
      const userKey = req.query.key;
      const correctKey = (config.masterUnlockKey || 'APEX-SOURCE-CODE-2026').trim().toLowerCase();
      const isAdminBypass = req.query.bypass === 'admin';
      
      if (!isAdminBypass && (!userKey || userKey.trim().toLowerCase() !== correctKey)) {
        return res.status(403).send('<h1>Access Denied</h1><p>A valid commercial license key is required to download this codebase. Please complete your payment first.</p>');
      }
    }

    // If there is an admin uploaded zip, serve it directly
    const uploadedPath = '/tmp/uploaded-source.zip';
    if (fs.existsSync(uploadedPath)) {
      console.log("Serving admin-uploaded source ZIP.");
      return res.download(uploadedPath, 'lms-full-source-code.zip');
    }

    // Clean up any old zip or tar file
    if (fs.existsSync('/tmp/source.zip')) {
      try { fs.unlinkSync('/tmp/source.zip'); } catch (e) {}
    }
    if (fs.existsSync('/tmp/source.tar.gz')) {
      try { fs.unlinkSync('/tmp/source.tar.gz'); } catch (e) {}
    }

    // Command to zip everything excluding node_modules, dist, git files, cache etc.
    const zipCommand = 'zip -r /tmp/source.zip . -x "node_modules/*" -x "dist/*" -x ".git/*" -x "*.zip" -x "*.tar.gz" -x ".npm/*" -x ".cache/*" -x ".local/*"';

    exec(zipCommand, (error) => {
      if (error) {
        console.warn("Native zip command failed, falling back to standard tar.gz packaging...", error);
        
        // Fallback to tar.gz which is guaranteed to be present on any Linux distribution
        const tarCommand = 'tar -czf /tmp/source.tar.gz . --exclude="node_modules" --exclude="dist" --exclude=".git" --exclude="*.zip" --exclude="*.tar.gz" --exclude=".npm" --exclude=".cache" --exclude=".local"';
        
        exec(tarCommand, (tarError) => {
          if (tarError) {
            console.error("Tar fallback also failed:", tarError);
            return res.status(500).json({ error: "Failed to package and compress source code." });
          }
          res.download('/tmp/source.tar.gz', 'lms-full-source-code.tar.gz');
        });
        return;
      }
      res.download('/tmp/source.zip', 'lms-full-source-code.zip');
    });
  });

